import itertools

def count_valid_colorings(M, N):
    # Precompute valid transitions between two rows
    valid_transitions = []
    for r1 in range(1 << N):
        for r2 in range(1 << N):
            is_valid = True
            for j in range(N - 1):
                s = (r1 & (1 << j)) + (r1 & (1 << (j+1))) + (r2 & (1 << j)) + (r2 & (1 << (j+1)))
                if s != 2:
                    is_valid = False
                    break
            if is_valid:
                valid_transitions.append((r1, r2))

    # Group transitions by current state for efficiency
    transitions_by_curr = [[] for _ in range(1 << N)]
    for r1, r2 in valid_transitions:
        transitions_by_curr[r2].append(r1)

    # DP initialization
    dp = [1] * (1 << N)

    # Iterate through rows
    for _ in range(M - 1):
        new_dp = [0] * (1 << N)
        for curr_state in range(1 << N):
            count = 0
            for prev_state in transitions_by_curr[curr_state]:
                count += dp[prev_state]
            new_dp[curr_state] = count
        dp = new_dp

    return sum(dp)

