                    s = grid[i][j] + grid[i+1][j] + grid[i][j+1] + grid[i+1][j+1]
                    if s != 2:
                        valid = False
                        break
                if not valid: break
            if valid: count += 1
        return count
    else:
        return count_valid_colorings(M, N)

